const deduped = playersData.filter((p, idx, arr) => arr.findIndex(q => q.name === p.name && q.country === p.country) === idx);
async function seed() {
    try {
        await mongoose_1.default.connect(config_1.config.mongodbUri);
        console.log('Connected to MongoDB');
        await Player_1.default.deleteMany({});
        console.log('Cleared existing players');
        const result = await Player_1.default.insertMany(deduped);
        console.log(`Seeded ${result.length} players successfully`);
        await mongoose_1.default.disconnect();
        console.log('Done');
    }
    catch (error) {
        console.error('Seed failed:', error);
        process.exit(1);
    }
}
seed();
